import { useState } from "react";
import "./Home.css";
import { FiUploadCloud, FiSearch } from "react-icons/fi";

function Home() {

    const [file, setFile] = useState(null);

    function handleUpload(event) {
        const selectedFile = event.target.files[0];
        setFile(selectedFile);
    }

    return (
        <div className="home">

            <header className="header">
                <h1>🛒 SMART RETAIL CHECKOUT AI</h1>   
            </header>

            <h2 className="title">
                The system automatically detects product prices and calculates the bill
            </h2>

            <div className="button-group">

                <input
                    type="file"
                    id="upload"
                    hidden
                    accept="image/*,video/*"
                    onChange={handleUpload}
                />

                <label htmlFor="upload" className="upload-btn">
                    <FiUploadCloud /> Upload Image / Video
                </label>

                <button className="detect-btn">
                    <FiSearch /> Detect Products
                </button>

            </div>

            <label htmlFor="upload" className="upload-box">

                <FiUploadCloud className="upload-icon" />

                <h2>Click to Upload</h2>

                <p>Supports JPG, PNG, JPEG and MP4</p>

                {file && <h4>{file.name}</h4>}

            </label>

            <div className="table-container">

                <h2>🛒 Shopping Cart</h2>

                <table>

                    <thead>

                        <tr>
                            <th>Product</th>
                            <th>Quantity</th>
                            <th>Price</th>
                            <th>Total</th>
                        </tr>

                    </thead>

                    <tbody>

                        <tr>
                            <td colSpan="4">
                                No products detected
                            </td>
                        </tr>

                    </tbody>

                </table>

            </div>

            <div className="summary">

                <div className="card">
                    <h3>Total Items</h3>
                    <h1>0</h1>
                </div>

                <div className="card">
                    <h3>Total Bill</h3>
                    <h1>₹0.00</h1>
                </div>

            </div>

        </div>
    );
}

export default Home;
